"""Classify provisioner background tasks that must outlive the agent AGUI stream."""

from __future__ import annotations

import asyncio
from typing import Any

PREREQ_WATCH_TASK_PREFIX = "prereq-watch-"


def is_prerequisite_watch_task(task: Any) -> bool:
    get_name = getattr(task, "get_name", None)
    if not callable(get_name):
        return False
    name = get_name()
    return isinstance(name, str) and name.startswith(PREREQ_WATCH_TASK_PREFIX)


def prerequisite_watch_tasks(tasks: list[Any]) -> list[Any]:
    return [task for task in tasks if is_prerequisite_watch_task(task)]


def cancellable_background_tasks(tasks: list[Any]) -> list[Any]:
    return [task for task in tasks if not is_prerequisite_watch_task(task)]


def prerequisite_tasks_pending(tasks: list[Any]) -> bool:
    return any(not task.done() for task in prerequisite_watch_tasks(tasks))


async def cancel_cancellable_background_tasks(tasks: list[Any]) -> None:
    pending = [task for task in cancellable_background_tasks(tasks) if not task.done()]
    for task in pending:
        task.cancel()
    if pending:
        await asyncio.gather(*pending, return_exceptions=True)


async def await_prerequisite_watch_tasks(tasks: list[Any]) -> None:
    pending = [task for task in prerequisite_watch_tasks(tasks) if not task.done()]
    if pending:
        await asyncio.gather(*pending, return_exceptions=True)

