@tool(
    name="run_bootstrap_in_terminal",
    description=(
        "Inject the bootstrap command into the shared embedded terminal for this session's "
        "environment. Use when the user says they finished sign-ins but the Proceed?/y/N "
        "prompt never appeared in the terminal. Runs scripts/run-bootstrap.sh (which "
        "re-verifies all sign-ins first) inside the user's tmux session so they see the output."
    ),
    requires_confirmation=False,
    stop_after_tool_call=False,
)
async def run_bootstrap_in_terminal(
    run_context: RunContext,
) -> dict[str, object]:
    session = _session(run_context)
    env_id = str(session.get(SESSION_ENVIRONMENT_ID, "")).strip()
    tmux_session = str(session.get(SESSION_TMUX_SESSION_NAME, "")).strip()

    if not env_id:
        return {
            "ok": False,
            "error": "No provisioned environment in this session — call start_dev_infra and bootstrap_terminal first.",
        }
    if not tmux_session:
        return {
            "ok": False,
            "error": "No shared terminal session found — call bootstrap_terminal first.",
        }

    transcript_dir = prerequisite_watcher.transcript_root / env_id
    transcript_dir.mkdir(parents=True, exist_ok=True)

    already_started = await prerequisite_watcher.ssh_client.run_bash_async(
        devpod_id=env_id,
        provider=prerequisite_watcher.devpod_settings.devpod_provider,
        script=build_bootstrap_started_check_script(),
        timeout_seconds=15,
        log_path=transcript_dir / "bootstrap-started-check.log",
        quiet_log=True,
    )
    if already_started.exit_code == 0:
        return {
            "ok": False,
            "already_started": True,
            "message": "Bootstrap is already running — check the embedded terminal for progress.",
        }

    workspace_dir = workspace_dir_for_environment(env_id)
    bash_command = f"cd {shlex.quote(workspace_dir)} && bash scripts/run-bootstrap.sh"
    keys = tmux_inject_keys(tmux_session_name=tmux_session, bash_command=bash_command)
    inject_script = build_tmux_send_keys_script(tmux_session_name=tmux_session, keys=keys)

    result = await prerequisite_watcher.ssh_client.run_bash_async(
        devpod_id=env_id,
        provider=prerequisite_watcher.devpod_settings.devpod_provider,
        script=inject_script,
        timeout_seconds=15,
        log_path=transcript_dir / "run-bootstrap-inject.log",
        quiet_log=True,
    )
    if result.exit_code != 0:
        return {
            "ok": False,
            "error": f"Failed to send bootstrap command to terminal: {result.stderr_tail}",
        }

    return {
        "ok": True,
        "message": "Bootstrap command sent — the user should see it running in the embedded terminal now.",
    }

return Toolkit(
    name="provisioner_coordinator_tools",
    tools=[start_dev_infra, bootstrap_terminal, run_bootstrap_in_terminal],
    add_instructions=False,
)
